// EF Core 9 breaking change: Migrate() now manages its own transactions
// internally, so wrapping it in an explicit transaction causes nesting errors.
// Remove the outer BeginTransaction/Commit and let Migrate() handle it.
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

