using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — fixes for EF Core 9 breaking changes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change #1: The Cosmos provider now defaults the
        // discriminator property name to "$type" instead of "Discriminator".
        // Existing documents already store "Discriminator", so we must
        // configure it explicitly to avoid query/deserialization failures.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }

    // EF Core 9 breaking change #2: Synchronous Cosmos DB I/O has been
    // removed entirely and now throws InvalidOperationException.
    // All queries and SaveChanges calls must use their async counterparts.
    //
    // BEFORE (breaks in EF Core 9):
    //   var items = db.Products.ToList();
    //   db.SaveChanges();
    //
    // AFTER:
    //   var items = await db.Products.ToListAsync();
    //   await db.SaveChangesAsync();
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

